import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10];

        // Copy only up to 10 characters from input to buffer
        int copyLength = Math.min(input.length(), 10);
        Arrays.copyOf(input.toCharArray(), copyLength, buffer.length);

        // Now the buffer will not overflow even if the user enters a longer string
    }
}

